package cmd

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"time"

	ddxagent "github.com/DocumentDrivenDX/ddx/internal/agent"
	ddxconfig "github.com/DocumentDrivenDX/ddx/internal/config"
	ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) newExecCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "exec",
		Short: "Validate and run DDx execution definitions",
		Long:  "Manage DDx execution definitions and immutable run history.",
		Run: func(cmd *cobra.Command, args []string) {
			_ = cmd.Help()
		},
	}

	cmd.AddCommand(f.newExecDefineCommand())
	cmd.AddCommand(f.newExecListCommand())
	cmd.AddCommand(f.newExecShowCommand())
	cmd.AddCommand(f.newExecValidateCommand())
	cmd.AddCommand(f.newExecRunCommand())
	cmd.AddCommand(f.newExecLogCommand())
	cmd.AddCommand(f.newExecResultCommand())
	cmd.AddCommand(f.newExecHistoryCommand())
	return cmd
}

func (f *CommandFactory) newExecDefineCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "define <name>",
		Short: "Create an execution definition",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			artifactID, _ := cmd.Flags().GetString("artifact")
			command, _ := cmd.Flags().GetString("command")
			execType, _ := cmd.Flags().GetString("type")

			if artifactID == "" {
				return fmt.Errorf("--artifact is required")
			}
			if command == "" {
				return fmt.Errorf("--command is required")
			}
			if execType == "" {
				execType = "check"
			}

			def := ddxexec.Definition{
				ID:          args[0],
				ArtifactIDs: []string{artifactID},
				Executor: ddxexec.ExecutorSpec{
					Kind:    ddxexec.ExecutorKindCommand,
					Command: strings.Fields(command),
				},
				Active:    true,
				CreatedAt: time.Now().UTC(),
			}
			_ = execType

			store := f.execStore()
			if err := store.SaveDefinition(def); err != nil {
				return err
			}
			fmt.Fprintln(cmd.OutOrStdout(), def.ID)
			return nil
		},
	}
	cmd.Flags().String("artifact", "", "Artifact ID to associate with this definition")
	cmd.Flags().String("command", "", "Command to execute")
	cmd.Flags().String("type", "", "Execution type: check, metric, or build (default: check)")
	return cmd
}

func (f *CommandFactory) execStore() *ddxexec.Store {
	store := ddxexec.NewStore(f.WorkingDir)
	if f.ExecAgentRunnerOverride != nil {
		store.AgentRunner = f.ExecAgentRunnerOverride
	} else {
		store.AgentRunner = serviceExecAgentRunner{workDir: f.WorkingDir}
	}
	return store
}

// serviceExecAgentRunner satisfies ddxexec.AgentRunner by dispatching through
// agent.RunWithConfigViaService. It replaces the retired f.agentRunner()
// factory which constructed a *agent.Runner only to call its Run method.
type serviceExecAgentRunner struct {
	workDir string
}

func (s serviceExecAgentRunner) Run(ctx context.Context, rcfg ddxconfig.ResolvedConfig, runtime ddxagent.AgentRunRuntime) (*ddxagent.Result, error) {
	return ddxagent.RunWithConfigViaService(ctx, s.workDir, rcfg, runtime)
}

func (f *CommandFactory) newExecListCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "list",
		Short: "List execution definitions",
		RunE: func(cmd *cobra.Command, args []string) error {
			artifactID, _ := cmd.Flags().GetString("artifact")
			defs, err := f.execStore().ListDefinitions(artifactID)
			if err != nil {
				return err
			}
			if cmd.Flags().Changed("json") {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(defs)
			}
			for _, def := range defs {
				fmt.Fprintf(cmd.OutOrStdout(), "%s  %s\n", def.ID, strings.Join(def.ArtifactIDs, ","))
			}
			return nil
		},
	}
	cmd.Flags().String("artifact", "", "Filter by artifact ID")
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newExecShowCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "show <definition-id>",
		Short: "Show one execution definition",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			def, err := f.execStore().ShowDefinition(args[0])
			if err != nil {
				return err
			}
			if cmd.Flags().Changed("json") {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(def)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "ID:       %s\n", def.ID)
			fmt.Fprintf(cmd.OutOrStdout(), "Artifacts:%s\n", strings.Join(def.ArtifactIDs, ", "))
			fmt.Fprintf(cmd.OutOrStdout(), "Kind:     %s\n", def.Executor.Kind)
			fmt.Fprintf(cmd.OutOrStdout(), "Created:  %s\n", def.CreatedAt.Format(time.RFC3339))
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newExecValidateCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "validate <definition-id>",
		Short: "Validate a definition and linked artifacts",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			def, doc, err := f.execStore().Validate(args[0])
			if err != nil {
				return err
			}
			if cmd.Flags().Changed("json") {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(map[string]any{
					"definition_id": def.ID,
					"artifact_id":   doc.ID,
					"status":        "ok",
				})
			}
			fmt.Fprintf(cmd.OutOrStdout(), "%s validated with %s\n", def.ID, doc.ID)
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newExecRunCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "run <definition-id>",
		Short: "Execute a definition and persist one run",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			rec, err := f.execStore().Run(cmd.Context(), args[0])
			if err != nil {
				return err
			}
			if cmd.Flags().Changed("json") {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(rec)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "%s  %s  %d\n", rec.RunID, rec.Status, rec.ExitCode)
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newExecLogCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "log <run-id>",
		Short: "Show raw logs for one run",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			stdout, stderr, err := f.execStore().Log(args[0])
			if err != nil {
				return err
			}
			if cmd.Flags().Changed("json") {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(map[string]string{"stdout": stdout, "stderr": stderr})
			}
			if stdout != "" {
				fmt.Fprintln(cmd.OutOrStdout(), stdout)
			}
			if stderr != "" {
				fmt.Fprintln(cmd.OutOrStdout(), stderr)
			}
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newExecResultCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "result <run-id>",
		Short: "Show structured result data for one run",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			result, err := f.execStore().Result(args[0])

		if filepath.IsAbs(def.Executor.Cwd) {
			cwd = def.Executor.Cwd
		} else {
			cwd = filepath.Join(s.WorkingDir, def.Executor.Cwd)
		}
	}

	cmd := osexec.CommandContext(ctx, def.Executor.Command[0], def.Executor.Command[1:]...)
	cmd.Dir = cwd
	if len(def.Executor.Env) > 0 {
		cmd.Env = append(os.Environ(), flattenEnv(def.Executor.Env)...)
	}

	start := time.Now().UTC()
	stdout, stderr, runErr := captureCommand(cmd)
	finished := time.Now().UTC()
	duration := finished.Sub(start)

	result := RunResult{
		Stdout: strings.TrimSpace(stdout),
		Stderr: strings.TrimSpace(stderr),
	}
	value, unit := normalizeMeasurement(stdout)
	if unit == "" && def.Result.Metric != nil {
		unit = def.Result.Metric.Unit
	}
	if unit != "" || value != 0 {
		result.Parsed = true
		result.Value = value
		result.Unit = unit
		result.Metric = &MetricObservation{
			ArtifactID:   doc.ID,
			DefinitionID: def.ID,
			ObservedAt:   start,
			Value:        value,
			Unit:         unit,
			Samples:      []float64{value},
		}
	}

	status := StatusSuccess
	exitCode := 0
	if runErr != nil {
		switch {
		case errors.Is(runErr, context.DeadlineExceeded):
			status = StatusTimedOut
		default:
			status = StatusFailed
		}
		var exitErr *osexec.ExitError
		if errors.As(runErr, &exitErr) {
			exitCode = exitErr.ExitCode()
		} else {
			exitCode = 1
		}
	}
	if result.Metric != nil {
		result.Metric.Status = metricStatusForRun(status)
		if status == StatusSuccess {
			result.Metric.Comparison = ComparisonResult{
				Baseline:  value,
				Delta:     0,
				Direction: def.Evaluation.Comparison,
			}
		}
	}

	runID := fmt.Sprintf("%s@%s-%d", def.ID, start.Format(time.RFC3339Nano), atomic.AddUint64(&s.runCounter, 1))
	record := RunRecord{
		RunManifest: RunManifest{
			RunID:            runID,
			DefinitionID:     def.ID,
			ArtifactIDs:      def.ArtifactIDs,
			ProducesArtifact: opts.ProducesArtifact,
			StartedAt:        start,
			FinishedAt:       finished,
			Status:           status,
			ExitCode:         exitCode,
			MergeBlocking:    def.Required && status != StatusSuccess,
			Attachments:      runAttachmentRefs(s.WorkingDir, runID),
			Provenance:       provenance(),
		},
		Result: result,
	}
	if writeErr := s.saveRunRecord(record); writeErr != nil {
		return RunRecord{}, writeErr
	}
	_ = duration
	return record, nil
}

func (s *Store) History(artifactID, definitionID string) ([]RunRecord, error) {
	entries, err := s.loadRuns()
	if err != nil {
		return nil, err
	}
	filtered := make([]RunRecord, 0, len(entries))
	for _, rec := range entries {
		if artifactID != "" && !containsString(rec.ArtifactIDs, artifactID) {
			continue
		}
		if definitionID != "" && rec.DefinitionID != definitionID {
			continue
		}
		filtered = append(filtered, rec)
	}
	return filtered, nil
}

func (s *Store) Log(runID string) (string, string, error) {
	rec, err := s.loadRunByID(runID)
	if err != nil {
		return "", "", err
	}
	return rec.Result.Stdout, rec.Result.Stderr, nil
}

func (s *Store) Result(runID string) (RunResult, error) {
	rec, err := s.loadRunByID(runID)
	if err != nil {
		return RunResult{}, err
	}
	return rec.Result, nil
}

func (s *Store) SaveDefinition(def Definition) error {
	if def.ID == "" {
		return fmt.Errorf("id is required")
	}
	if len(def.ArtifactIDs) == 0 {
		return fmt.Errorf("artifact_ids is required")
	}
	return s.saveDefinitionBead(def)
}

func (s *Store) readRunBundle(dir string) (RunRecord, error) {
	manifestRaw, err := os.ReadFile(filepath.Join(dir, "manifest.json"))
	if err != nil {
		return RunRecord{}, err
	}
	resultRaw, err := os.ReadFile(filepath.Join(dir, "result.json"))
	if err != nil {
		return RunRecord{}, err
	}
	var manifest RunManifest
	if err := json.Unmarshal(manifestRaw, &manifest); err != nil {
		return RunRecord{}, err
	}
	var result RunResult
	if err := json.Unmarshal(resultRaw, &result); err != nil {
		return RunRecord{}, err
	}
	return RunRecord{RunManifest: manifest, Result: result}, nil
}

func syncPath(path string) error {
	f, err := os.Open(path)
	if err != nil {
		return err
	}
	defer f.Close()
	return f.Sync()
}

func provenance() Provenance {
	host, _ := os.Hostname()
	return Provenance{Host: host}
}

func containsString(values []string, target string) bool {
	for _, value := range values {
		if value == target {
			return true
		}
	}
	return false
}

func flattenEnv(values map[string]string) []string {
	out := make([]string, 0, len(values))
	for key, value := range values {
		out = append(out, fmt.Sprintf("%s=%s", key, value))
	}
	sort.Strings(out)
	return out
}

func captureCommand(cmd *osexec.Cmd) (string, string, error) {
	var stdoutBuf, stderrBuf strings.Builder
	cmd.Stdout = &stdoutBuf
	cmd.Stderr = &stderrBuf
	err := cmd.Run()
	return stdoutBuf.String(), stderrBuf.String(), err
}

var measurementPattern = regexp.MustCompile(`(?i)(-?\d+(?:\.\d+)?)(?:\s*)(ms|s|sec|seconds?)?`)

func normalizeMeasurement(stdout string) (float64, string) {
	trimmed := strings.TrimSpace(stdout)
	if trimmed == "" {
		return 0, ""
	}
	if value, unit, ok := parseJSONMeasurement(trimmed); ok {
		return value, unit
	}
	if value, unit, ok := parseTextMeasurement(trimmed); ok {
		return value, unit
	}
	return 0, ""
}

func parseJSONMeasurement(text string) (float64, string, bool) {
	var obj map[string]any
	if err := json.Unmarshal([]byte(text), &obj); err != nil {
		return 0, "", false
	}
	if raw, ok := obj["value"]; ok {
		switch v := raw.(type) {
		case float64:
			unit, _ := obj["unit"].(string)
			return v, unit, true
		case string:
			if parsed, err := strconv.ParseFloat(v, 64); err == nil {
				unit, _ := obj["unit"].(string)
				return parsed, unit, true
			}
		}
	}
	return 0, "", false
}

func parseTextMeasurement(text string) (float64, string, bool) {
	match := measurementPattern.FindStringSubmatch(text)
	if len(match) < 2 {
		return 0, "", false
	}
	value, err := strconv.ParseFloat(match[1], 64)
	if err != nil {
		return 0, "", false
	}
	unit := ""
	if len(match) >= 3 {
		unit = strings.ToLower(match[2])
	}
	return value, unit, true
}

func metricStatusForRun(status string) string {
	if status == StatusSuccess {
		return "pass"
	}
	return "fail"
}

func genAgentSessionID() string {
	b := make([]byte, 4)
	_, _ = rand.Read(b)
