351	func (s *Store) History(artifactID, definitionID string) ([]RunRecord, error) {
352		entries, err := s.loadRuns()
353		if err != nil {
354			return nil, err
355		}
356		filtered := make([]RunRecord, 0, len(entries))
357		for _, rec := range entries {
358			if artifactID != "" && !containsString(rec.ArtifactIDs, artifactID) {
359				continue
360			}
361			if definitionID != "" && rec.DefinitionID != definitionID {
362				continue
363			}
364			filtered = append(filtered, rec)
365		}
366		return filtered, nil
367	}
