23	func keepExecReachability() {
24		if os.Getenv("DDX_EXEC_KEEPALIVE") != "1" {
25			return
26		}
27	
28		workingDir, err := os.MkdirTemp("", "ddx-exec-keepalive")
29		if err != nil {
30			return
31		}
32		defer os.RemoveAll(workingDir)
33	
34		store := NewStore(workingDir)
35		if store.DefinitionCollection != nil {
36			_ = store.DefinitionCollection.Init()
37		}
38		if store.RunCollection != nil {
39			_ = store.RunCollection.Init()
40		}
41	
42		artifactID := "MET-KEEPALIVE"
43		artifactPath := filepath.Join(workingDir, "docs", "metrics", artifactID+".md")
44		if err := os.MkdirAll(filepath.Dir(artifactPath), 0o755); err != nil {
45			return
46		}
47		artifactContent := "---\nddx:\n  id: " + artifactID + "\n---\n# " + artifactID + "\n"
48		if err := os.WriteFile(artifactPath, []byte(artifactContent), 0o644); err != nil {
49			return
50		}
51	
52		definitionID := "exec-keepalive@1"
53		def := Definition{
54			ID:          definitionID,
55			ArtifactIDs: []string{artifactID},
56			Executor: ExecutorSpec{
57				Kind:    ExecutorKindCommand,
58				Command: []string{"sh", "-c", "printf 'keepalive\\n'"},
59			},
60			Active:    true,
61			CreatedAt: time.Unix(0, 0).UTC(),
62		}
63		_ = store.SaveDefinition(def)
64	
65		rec, err := store.Run(context.Background(), definitionID)
66		if err != nil {
67			return
68		}
69		_, _ = store.History(artifactID, "")
70		_, _, _ = store.Log(rec.RunID)
71		_, _ = store.Result(rec.RunID)
72	}

